import{_ as e,o as t,c as r,a2 as o}from"./chunks/framework.DZ4hGonn.js";const u=JSON.parse('{"title":"博客上线：代码·专利·哲学·音乐四维空间","description":"cmaz501 个人博客正式上线，聚焦代码、专利、哲学、音乐四个维度，记录探索与思考。","frontmatter":{"title":"博客上线：代码·专利·哲学·音乐四维空间","date":"2026-07-15T00:00:00.000Z","author":"cmaz501","description":"cmaz501 个人博客正式上线，聚焦代码、专利、哲学、音乐四个维度，记录探索与思考。","tags":["公告","博客","cmaz501"]},"headers":[],"relativePath":"about/first-post.md","filePath":"about/first-post.md","lastUpdated":1784180794000}'),s={name:"about/first-post.md"};function i(n,a,l,h,p,d){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="博客上线-代码·专利·哲学·音乐四维空间" tabindex="-1">博客上线：代码·专利·哲学·音乐四维空间 <a class="header-anchor" href="#博客上线-代码·专利·哲学·音乐四维空间" aria-label="Permalink to &quot;博客上线：代码·专利·哲学·音乐四维空间&quot;">​</a></h1><p>今天，这个博客正式上线了。</p><h2 id="为什么建这个博客" tabindex="-1">为什么建这个博客 <a class="header-anchor" href="#为什么建这个博客" aria-label="Permalink to &quot;为什么建这个博客&quot;">​</a></h2><p>互联网不缺内容，缺的是经过思考的、结构化的人个知识沉淀。</p><p>我每天在几个不同的领域之间切换——写代码、研究专利、读哲学、听音乐。以前这些思考散落在笔记软件、聊天记录、浏览器收藏夹里，碎片化严重。这个博客给它们一个家。</p><h2 id="四个维度" tabindex="-1">四个维度 <a class="header-anchor" href="#四个维度" aria-label="Permalink to &quot;四个维度&quot;">​</a></h2><h3 id="💻-代码" tabindex="-1">💻 代码 <a class="header-anchor" href="#💻-代码" aria-label="Permalink to &quot;💻 代码&quot;">​</a></h3><p>技术笔记和工程实践。前端、后端、DevOps、开源项目——写过的代码，踩过的坑，都值得被记录。</p><h3 id="📜-专利" tabindex="-1">📜 专利 <a class="header-anchor" href="#📜-专利" aria-label="Permalink to &quot;📜 专利&quot;">​</a></h3><p>知识产权探索。专利撰写、战略布局、侵权分析。这是 <strong>金石意象</strong> 的核心领域：用严谨的法律逻辑为创新护航。</p><h3 id="🧠-哲学" tabindex="-1">🧠 哲学 <a class="header-anchor" href="#🧠-哲学" aria-label="Permalink to &quot;🧠 哲学&quot;">​</a></h3><p>不是学院派哲学，而是对技术时代问题的思考。AI 伦理、意识本质、语言边界——代码写累了，抬头看看更大的问题。</p><h3 id="🎵-音乐" tabindex="-1">🎵 音乐 <a class="header-anchor" href="#🎵-音乐" aria-label="Permalink to &quot;🎵 音乐&quot;">​</a></h3><p>耳朵不会骗人。乐评、理论、创作笔记——从 Debussy 到电子音乐，记录每一次心动。</p><h2 id="技术选型" tabindex="-1">技术选型 <a class="header-anchor" href="#技术选型" aria-label="Permalink to &quot;技术选型&quot;">​</a></h2><p>这个博客基于 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a> 构建，部署在 <a href="https://vercel.com/" target="_blank" rel="noreferrer">Vercel</a> 上。</p><p>选 VitePress 的理由很简单：</p><ul><li><strong>纯 Markdown 写作</strong>，不依赖数据库</li><li><strong>构建速度极快</strong>（Vite 驱动，2 秒内完成）</li><li><strong>零成本部署</strong>（Vercel 免费额度完全够用）</li><li><strong>开源可控</strong>，不会被平台绑架</li></ul><h2 id="关于我" tabindex="-1">关于我 <a class="header-anchor" href="#关于我" aria-label="Permalink to &quot;关于我&quot;">​</a></h2><p>我是 <strong>cmaz501</strong>（也是 <strong>TjayLeaf</strong>），<a href="https://github.com/cmaz501" target="_blank" rel="noreferrer">开迈科技</a> 的探索者，<strong>金石意象</strong> 的思考者。</p><p>这个地方不求流量，只求质量。欢迎同道中人。</p><hr><p><em>第一篇文章，草草起笔。但愿往后每一篇，都比这篇更好。</em></p>',23)])])}const f=e(s,[["render",i]]);export{u as __pageData,f as default};
